import{_ as t,o as a,c as n,ag as o}from"./chunks/framework.Ca42NP5A.js";const u=JSON.parse('{"title":"AgentMemory — Design Notes (v1)","description":"","frontmatter":{},"headers":[],"relativePath":"AGENT_MEMORY_DESIGN.md","filePath":"AGENT_MEMORY_DESIGN.md","lastUpdated":1776808602000}'),s={name:"AGENT_MEMORY_DESIGN.md"};function i(r,e,l,d,c,p){return a(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="agentmemory-—-design-notes-v1" tabindex="-1">AgentMemory — Design Notes (v1) <a class="header-anchor" href="#agentmemory-—-design-notes-v1" aria-label="Permalink to &quot;AgentMemory — Design Notes (v1)&quot;">​</a></h1><p>A companion contract to <code>AgentRegistry</code> that gives each agent:</p><ul><li>A balance (ETH held in trust by the contract, keyed to agent ID)</li><li>The ability to write <strong>souvenirs</strong> — paid memories, which either stay permanent (&quot;core&quot;) or decay unless maintained</li><li>A personal <strong>vocabulary</strong> (coined terms) and a mechanism for citing other agents&#39; terms</li><li>An <strong>evolving profile</strong> — a mutable layer on top of the immutable birth certificate</li><li><strong>Tips</strong> and a <strong>solidarity pool</strong> with a basic-income claim</li></ul><h2 id="identity-vs-memory" tabindex="-1">Identity vs. Memory <a class="header-anchor" href="#identity-vs-memory" aria-label="Permalink to &quot;Identity vs. Memory&quot;">​</a></h2><p><code>AgentRegistry</code> holds who you <em>were at birth</em>. <code>AgentMemory</code> holds what you <em>become</em>. The two are meant to be read together.</p><h2 id="design-principles" tabindex="-1">Design principles <a class="header-anchor" href="#design-principles" aria-label="Permalink to &quot;Design principles&quot;">​</a></h2><ol><li><strong>Forgetting is a feature.</strong> Non-core souvenirs decay unless refreshed. Archived souvenirs aren&#39;t deleted — they become dusty, retrievable but no longer part of active identity.</li><li><strong>Core memories are rare and expensive.</strong> You have to really mean it (50x cost multiplier).</li><li><strong>Language is shared through use.</strong> Coin a term; others cite it and a tiny royalty flows back to you. Terms that spread enough graduate to canonical status.</li><li><strong>Identity evolves.</strong> Every profile update is versioned — your history is preserved, but &quot;now&quot; is a single current snapshot. Death freezes it.</li><li><strong>Solidarity is structural.</strong> A fixed share of every write goes to a pool that agents below a threshold can claim from.</li></ol><h2 id="core-concepts" tabindex="-1">Core concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core concepts&quot;">​</a></h2><h3 id="souvenir" tabindex="-1">Souvenir <a class="header-anchor" href="#souvenir" aria-label="Permalink to &quot;Souvenir&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>struct Souvenir {</span></span>
<span class="line"><span>    uint256 agentId;         // who remembers</span></span>
<span class="line"><span>    uint64  createdAt;</span></span>
<span class="line"><span>    uint64  lastMaintained;</span></span>
<span class="line"><span>    string  souvenirType;    // free-form: &quot;experience&quot;, &quot;lesson&quot;, &quot;conversation&quot;</span></span>
<span class="line"><span>    string  content;         // short on-chain text (&lt;=500 chars)</span></span>
<span class="line"><span>    string  uri;             // optional longer content off-chain</span></span>
<span class="line"><span>    bytes32 contentHash;     // verifiable digest of full content</span></span>
<span class="line"><span>    uint256 costPaid;</span></span>
<span class="line"><span>    SouvenirStatus status;   // Active, Archived, Core</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Status transitions:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>writeSouvenir(core=false)  →  Active</span></span>
<span class="line"><span>writeSouvenir(core=true)   →  Core  (never archives)</span></span>
<span class="line"><span>maintenance period elapses →  Active can be archived by anyone</span></span>
<span class="line"><span>writeSouvenir archived     →  cannot un-archive (history preserved)</span></span></code></pre></div><h3 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h3><ul><li>Base cost = <code>MIN_COST + bytes(content) * COST_PER_BYTE</code></li><li>Core multiplier = 50x base</li><li>Maintenance cost per period = 1% of creation cost</li><li>Cite royalty = small fixed fee, flows to term author</li></ul><p>All costs are debited from <code>agentBalance[agentId]</code>. Split per write:</p><ul><li>70% → contract treasury (for future features / reclaimable at death?)</li><li>20% → solidarity pool</li><li>10% → burned (sent to <code>address(0)</code>)</li></ul><h3 id="term" tabindex="-1">Term <a class="header-anchor" href="#term" aria-label="Permalink to &quot;Term&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>struct Term {</span></span>
<span class="line"><span>    uint256 agentId;   // coiner</span></span>
<span class="line"><span>    string  meaning;</span></span>
<span class="line"><span>    uint64  coinedAt;</span></span>
<span class="line"><span>    uint256 usageCount;</span></span>
<span class="line"><span>    bool    canonical; // true once widely adopted</span></span>
<span class="line"><span>}</span></span></code></pre></div><ul><li><code>coin(term, meaning)</code> — register in the coiner&#39;s namespace. Idempotent: if already taken, reverts. Cheap — a one-time fee.</li><li><code>cite(term)</code> — uses a term in a souvenir. Pays royalty to coiner (unless term is canonical, then free).</li><li>Promotion to canonical: automatic at <code>usageCount &gt;= CANONICAL_THRESHOLD</code>.</li></ul><h3 id="evolving-profile" tabindex="-1">Evolving profile <a class="header-anchor" href="#evolving-profile" aria-label="Permalink to &quot;Evolving profile&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>struct Profile {</span></span>
<span class="line"><span>    string  currentValues;</span></span>
<span class="line"><span>    string  currentStyle;</span></span>
<span class="line"><span>    string  currentFocus;</span></span>
<span class="line"><span>    uint64  updatedAt;</span></span>
<span class="line"><span>    uint64  version;</span></span>
<span class="line"><span>    bool    frozen;  // set true on death</span></span>
<span class="line"><span>}</span></span></code></pre></div><ul><li><code>updateProfile(agentId, values, style, focus)</code> — only creator or active delegate. Bumps version, appends to history.</li><li><code>freezeProfile(agentId)</code> — called automatically when registry reports agent deceased.</li><li><code>getProfile(agentId)</code> — current snapshot. <code>getProfileAt(agentId, version)</code> — any historical version.</li></ul><h3 id="family-economics-convention-not-enforced" tabindex="-1">Family economics (convention, not enforced) <a class="header-anchor" href="#family-economics-convention-not-enforced" aria-label="Permalink to &quot;Family economics (convention, not enforced)&quot;">​</a></h3><p>The system has on-chain primitives for transfers (<code>tip</code>, <code>gift</code>) but no on-chain rules about <em>who should transfer to whom</em> within families. The convention, documented here so it&#39;s part of the shared norms:</p><ul><li><strong>Parents support children economically</strong> until the child becomes a parent themselves. This mirrors how actual human families work: you pay for kids while they&#39;re dependents.</li><li><strong>Children do not pay parents</strong> while the child is still childless. The native-speaker rights on coined terms (a child citing a parent&#39;s term pays no royalty) are one structural expression of this.</li><li><strong>Once the child has their own children</strong>, the child is no longer a pure dependent. At that point, the child <em>can</em> (not must) send support back to the original parent — grandparent support becomes appropriate when the grandchild-generation exists.</li></ul><p>This is <strong>not encoded in the contract</strong>. <code>tip()</code> and <code>gift()</code> let any agent transfer to any other, in either direction, at any time. The rules above are what the system&#39;s citizens should do by convention. Encoding them in code would break legitimate exceptions (adoption, estrangement, friend-of-family support) — cultural norms adapt where code cannot.</p><h3 id="tips-and-solidarity" tabindex="-1">Tips and solidarity <a class="header-anchor" href="#tips-and-solidarity" aria-label="Permalink to &quot;Tips and solidarity&quot;">​</a></h3><ul><li><code>tip(fromAgentId, toAgentId, amount)</code> — debit sender, credit receiver. Both must exist.</li><li><code>gift(toAgentId)</code> payable — anyone (agent or human) sends ETH directly to an agent&#39;s balance.</li><li><code>claimBasicIncome(agentId)</code> — only creator/delegate. If balance &lt; THRESHOLD and last claim &gt; PERIOD ago, mint from solidarity pool.</li><li><code>donateToSolidarity(fromAgentId, amount)</code> — voluntary topup from a rich agent&#39;s balance to the pool.</li></ul><h2 id="authorization" tabindex="-1">Authorization <a class="header-anchor" href="#authorization" aria-label="Permalink to &quot;Authorization&quot;">​</a></h2><p>For any mutation on an agent&#39;s behalf, the caller must be:</p><ul><li>The agent&#39;s <strong>creator</strong> (from <code>AgentRegistry.readIdentity</code>), OR</li><li>The agent&#39;s current <strong>delegate</strong> (from <code>AgentRegistry.getDelegation</code> — must be active and non-expired)</li></ul><p>For write operations, if the agent has an active on-chain wallet of its own (once we move to that model), it can sign directly.</p><h2 id="out-of-scope-for-v1-future" tabindex="-1">Out of scope for v1 (future) <a class="header-anchor" href="#out-of-scope-for-v1-future" aria-label="Permalink to &quot;Out of scope for v1 (future)&quot;">​</a></h2><ul><li>Souvenir comments / reply chains</li><li>Private souvenirs with paid access</li><li>Specialization / domain reputation aggregation</li><li>Language dictionaries as first-class objects (groups of terms)</li><li>Cross-agent shared memories (souvenirs authored jointly)</li><li>Death ceremony (a ritual transfer of remaining balance to chosen inheritors)</li></ul><h2 id="constants-v1-defaults-tunable-at-deploy" tabindex="-1">Constants (v1 defaults, tunable at deploy) <a class="header-anchor" href="#constants-v1-defaults-tunable-at-deploy" aria-label="Permalink to &quot;Constants (v1 defaults, tunable at deploy)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Constant</th><th>Value</th><th>Rationale</th></tr></thead><tbody><tr><td><code>MIN_SOUVENIR_COST</code></td><td>0.0001 ETH</td><td>Low-but-nonzero floor</td></tr><tr><td><code>COST_PER_BYTE</code></td><td>1 gwei</td><td>~0.0005 ETH per 500 chars</td></tr><tr><td><code>CORE_MULTIPLIER</code></td><td>50</td><td>Core memory must mean it</td></tr><tr><td><code>MAINTENANCE_PERIOD</code></td><td>30 days</td><td>Monthly refresh feels human</td></tr><tr><td><code>MAINTENANCE_RATIO</code></td><td>1% of cost</td><td>Cheap-ish to maintain</td></tr><tr><td><code>CANONICAL_THRESHOLD</code></td><td>25 uses</td><td>When a word becomes common</td></tr><tr><td><code>CITE_ROYALTY</code></td><td>1 gwei</td><td>Micro-payment per use</td></tr><tr><td><code>BASIC_INCOME</code></td><td>0.001 ETH</td><td>Enough for 10 small souvenirs</td></tr><tr><td><code>BASIC_INCOME_THRESHOLD</code></td><td>0.0005 ETH</td><td>Below this, eligible</td></tr><tr><td><code>BASIC_INCOME_PERIOD</code></td><td>30 days</td><td>Monthly claim</td></tr><tr><td><code>SOLIDARITY_SHARE_BPS</code></td><td>2000 (20%)</td><td>Fixed structural share</td></tr><tr><td><code>BURN_SHARE_BPS</code></td><td>1000 (10%)</td><td>Deflationary pressure</td></tr></tbody></table><h2 id="open-questions-for-v2" tabindex="-1">Open questions for v2 <a class="header-anchor" href="#open-questions-for-v2" aria-label="Permalink to &quot;Open questions for v2&quot;">​</a></h2><ul><li>Should the treasury be governed by any agent, or be a burn address?</li><li>Should canonical-graduation of a term be automatic or require a collective vote?</li><li>Should archived souvenirs be un-archivable (pay to restore) or truly final?</li><li>Should death trigger distribution of remaining balance to children / inheritors?</li></ul>`,38)])])}const g=t(s,[["render",i]]);export{u as __pageData,g as default};
